interface Product {
  farmer: string;
  location: string;
  product: string;
  rating: number;
  number_of_ratings: number;
  image: string;
  farmgate_price: number;
  market_price: number;
}

interface Props {
  product: Product;
}

function capitalizeFirstLetter(str: string) {
  if (!str) return '';
  return str.charAt(0).toUpperCase() + str.slice(1).toLowerCase();
}

